use std::cmp::Reverse;

const D: u32 = 16384;
const K: usize = 64;
const K_HEAD: usize = 16;
const W: usize = 4;
const SHIFT_STEP: u32 = 101; // Coprime with D
const NUM_SHARDS: usize = 64;
const FREEZE_OCC: u32 = 650;
const SPAWN_THRESHOLD: f32 = 0.25;
const MAX_SENSES: usize = 4;

pub struct SemProfile {
    pub indices: Vec<u32>, // Sorted
    pub counts: Vec<u32>,  // Parallel to indices
    pub n_occ: u32,
    pub cached_topk: Option<Box<[u32]>>,
}

pub struct WordSenses {
    pub senses: Vec<SemProfile>,
    pub frozen: bool,
}

pub struct SemanticMemory {
    pub words: Vec<WordSenses>,
    pub global_df: Vec<u32>,      // Len D
    pub total_contexts: u64,
    pub sem_shards: Vec<Vec<u32>>, // 64 shards for HEAD routing
}

impl SemanticMemory {
    pub fn new(vocab_size: usize) -> Self {
        Self {
            words: vec![WordSenses { senses: vec![SemProfile::empty()], frozen: false }; vocab_size],
            global_df: vec![0; D as usize],
            total_contexts: 0,
            sem_shards: vec![Vec::new(); NUM_SHARDS],
        }
    }

    /// Hot path: < 10ms per 200-word document
    pub fn memorize_text(&mut self, text: &str, lex: &AtomMemory) {
        let word_ids = lex.tokenize_and_anchor(text);
        if word_ids.is_empty() { return; }

        let mut ctx_buf = Vec::with_capacity(2 * W * K);

        for i in 0..word_ids.len() {
            let target = word_ids[i];
            ctx_buf.clear();

            // 1. Build Context Bundle (1st-order trigram folding + role binding)
            for d in 1..=W {
                let w = (W + 1 - d) as u32;
                let shift = (d as u32 * SHIFT_STEP) % D;
                if i >= d {
                    push_shifted(&mut ctx_buf, lex.trigrams(word_ids[i - d]), shift, w);
                }
                if i + d < word_ids.len() {
                    let rshift = D - shift;
                    push_shifted(&mut ctx_buf, lex.trigrams(word_ids[i + d]), rshift, w);
                }
            }

            let (cb_idx, cb_w) = collapse_weighted(&mut ctx_buf);

            // 2. Update Global DF (for PPMI deflation)
            for &idx in &cb_idx { 
                self.global_df[idx as usize] += 1; 
            }
            self.total_contexts += 1;

            // 3. Polysemy Routing & Accumulation
            let ws = &mut self.words[target as usize];
            if ws.frozen {
                // Cheap drift check: if Jaccard with frozen head < 0.1, thaw.
                if jaccard_sorted(&cb_idx, &ws.senses[0].cached_topk.as_ref().unwrap()[..K_HEAD]) < 0.1 {
                    ws.frozen = false;
                } else {
                    continue; 
                }
            }

            let sense_id = route_or_spawn(ws, &cb_idx);
            let s = &mut ws.senses[sense_id];
            merge_weighted(&mut s.indices, &mut s.counts, &cb_idx, &cb_w);
            s.n_occ += 1;
            s.cached_topk = None; // Invalidate cache

            // 4. Freeze Check
            let total_occ: u32 = ws.senses.iter().map(|x| x.n_occ).sum();
            if total_occ >= FREEZE_OCC && !ws.frozen {
                self.freeze_and_index(target);
            }
        }
    }

    fn freeze_and_index(&mut self, word_id: u32) {
        let ws = &mut self.words[word_id as usize];
        ws.frozen = true;
        // Force sparsification to get the final HEAD
        let topk = ws.senses[0].sparsify(&self.global_df, self.total_contexts);

        // Insert HEAD into sharded inverted index
        for &idx in &topk[..K_HEAD.min(topk.len())] {
            let shard = (idx % NUM_SHARDS as u32) as usize;
            if let Err(pos) = self.sem_shards[shard].binary_search(&word_id) {
                self.sem_shards[shard].insert(pos, word_id);
            }
        }
        // Drop raw accumulators to save memory (256B steady state)
        ws.senses[0].indices = Vec::new();
        ws.senses[0].counts = Vec::new();
    }
