impl SemProfile {
    pub fn empty() -> Self {
        Self { indices: Vec::new(), counts: Vec::new(), n_occ: 0, cached_topk: None }
    }

    /// PPMI Deflation at Read-Time (Claude's R3 correction)
    pub fn sparsify(&mut self, global_df: &[u32], total_ctx: u64) -> &[u32] {
        if self.cached_topk.is_none() {
            let mut scored: Vec<(u32, u32)> = self.indices.iter().zip(self.counts.iter())
                .map(|(&idx, &c)| {
                    let df = global_df[idx as usize] as f32;
                    // PPMI: log( (N + 1) / (df + 1) )
                    let idf = ((total_ctx as f32 + 1.0) / (df + 1.0)).ln_1p();
                    (idx, (c as f32 * idf) as u32) 
                })
                .collect();

            let k = K.min(scored.len());
            if k > 0 {
                scored.select_nth_unstable_by_key(k - 1, |x| Reverse(x.1));
                scored.truncate(k);
            }

            let mut topk: Vec<u32> = scored.into_iter().map(|x| x.0).collect();
            topk.sort_unstable();
            self.cached_topk = Some(topk.into_boxed_slice());
        }
        self.cached_topk.as_ref().unwrap()
    }
}
